  } catch {
    // ignore
  }
  try {
    dbh.exec(`
      CREATE INDEX IF NOT EXISTS idx_properties_plot_plate_apt
      ON properties(
        TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_┘é╪╖╪╣╪⌐"'), '')),
        TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_┘ä┘ê╪¡╪⌐"'), '')),
        TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_╪┤┘é╪⌐"'), ''))
      )
      WHERE TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_┘é╪╖╪╣╪⌐"'), '')) <> ''
        AND TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_┘ä┘ê╪¡╪⌐"'), '')) <> ''
        AND TRIM(COALESCE(JSON_EXTRACT(data, '$."╪▒┘é┘à_╪┤┘é╪⌐"'), '')) <> ''
