          property = undefined;
        }
      }
    }

    let tenant: unknown | undefined;
    if (tid) {
      const tr = dbh.prepare('SELECT data FROM people WHERE id = ? LIMIT 1').get(tid) as
        | { data?: string }
        | undefined;
      if (tr?.data) {
        try {
          tenant = JSON.parse(String(tr.data || ''));
