    const installments = instRows
      .map((r) => {
        try {
          return JSON.parse(String(r.data || ''));
        } catch {
          return null;
        }
      })
      .filter((x): x is unknown => Boolean(x));

    // Keep legacy ordering semantics when rank is available.
    installments.sort((a, b) => {
      const aRec = toRecord(a);
      const bRec = toRecord(b);

      const ar = toNumber(aRec['╪¬╪▒╪¬┘è╪¿_╪º┘ä┘â┘à╪¿┘è╪º┘ä╪⌐'] ?? aRec.rank);
      const br = toNumber(bRec['╪¬╪▒╪¬┘è╪¿_╪º┘ä┘â┘à╪¿┘è╪º┘ä╪⌐'] ?? bRec.rank);
      if (ar !== br) return ar - br;

      return String(aRec['╪¬╪º╪▒┘è╪«_╪º╪│╪¬╪¡┘é╪º┘é'] ?? aRec.dueDate ?? '').localeCompare(
        String(bRec['╪¬╪º╪▒┘è╪«_╪º╪│╪¬╪¡┘é╪º┘é'] ?? bRec.dueDate ?? '')
      );
    });

    return { ok: true, data: { contract, property, tenant, installments } };
  } catch (e: unknown) {
    const message =
      e instanceof Error ? e.message : typeof e === 'string' ? e : '┘ü╪┤┘ä ╪¬╪¡┘à┘è┘ä ╪¬┘ü╪º╪╡┘è┘ä ╪º┘ä╪╣┘é╪»';
