      return {
        ok: true,
        result: {
          title: '╪º┘ä╪ú┘é╪│╪º╪╖ ╪º┘ä┘à╪¬╪ú╪«╪▒╪⌐',
          generatedAt,
          columns: [
            { key: 'tenant', header: '╪º┘ä┘à╪│╪¬╪ú╪¼╪▒' },
            { key: 'property', header: '╪º┘ä╪╣┘é╪º╪▒' },
            { key: 'dueDate', header: '╪¬╪º╪▒┘è╪« ╪º┘ä╪º╪│╪¬╪¡┘é╪º┘é', type: 'date' },
