          WHERE (c.isArchived IS NULL OR c.isArchived = 0)
            AND c.status IN ('┘å╪┤╪╖', '┘é╪▒┘è╪¿ ╪º┘ä╪º┘å╪¬┘ç╪º╪í', '┘à╪¼╪»╪»')
          ORDER BY c.endDate ASC
          LIMIT ?
        `
        )
        .all(cap) as Array<{
        contractNo: string;
        tenant: string;
        property: string;
        startDate: string;
        endDate: string;
        monthlyRent: number;
        status: string;
      }>;

      const data = rows.map((r) => ({
