      return {
        ok: true,
        result: {
          title: '╪º┘ä╪╣┘é┘ê╪» ╪º┘ä╪│╪º╪▒┘è╪⌐',
          generatedAt,
          columns: [
            { key: 'contractNo', header: '╪▒┘é┘à ╪º┘ä╪╣┘é╪»' },
