export type SqlPullApplyResult = 'upsert' | 'delete' | 'skipped';

export async function applySqlRemoteKvRow(row: {
  k: string;
  v: string;
  updatedAt: string;
  isDeleted: boolean;
}): Promise<SqlPullApplyResult> {
  const localMeta = kvGetMeta(row.k);
  const localDeletedAt = kvGetDeletedAt(row.k);
  const localBestTs = localDeletedAt || localMeta?.updatedAt || '';

  const remoteTs = row.updatedAt;
  const isRemoteNewer =
    !localBestTs || new Date(remoteTs).getTime() > new Date(localBestTs).getTime();
  if (!isRemoteNewer) return 'skipped';

  if (row.isDeleted) {
    kvApplyRemoteDelete(row.k, remoteTs);
    broadcastDbRemoteUpdate({ key: row.k, isDeleted: true, updatedAt: remoteTs });
    addSqlSyncLogEntry({
      direction: 'pull',
      action: 'delete',
      key: row.k,
      status: 'ok',
      ts: remoteTs,
    });
    return 'delete';
  }

  kvSetWithUpdatedAt(row.k, row.v, remoteTs);
  broadcastDbRemoteUpdate({
    key: row.k,
    value: row.v,
    isDeleted: false,
    updatedAt: remoteTs,
  });
  addSqlSyncLogEntry({
    direction: 'pull',
    action: 'upsert',
    key: row.k,
    status: 'ok',
    ts: remoteTs,
  });

  if (row.k === 'db_attachments') {
    try {
      const res = await pullAttachmentFilesForAttachmentsJson(row.v);
      if (res.downloaded > 0) {
        addSqlSyncLogEntry({
          direction: 'system',
          action: 'attachments:pull',
          status: 'ok',
          message: `╪¬┘à ╪¬┘å╪▓┘è┘ä ${res.downloaded} ┘à╪▒┘ü┘é/┘à╪▒┘ü┘é╪º╪¬`,
        });
      }
      if (res.missingRemote > 0) {
        addSqlSyncLogEntry({
          direction: 'system',
          action: 'attachments:pull',
          status: 'error',
          message: `┘à╪▒┘ü┘é╪º╪¬ ╪║┘è╪▒ ┘à┘ê╪¼┘ê╪»╪⌐ ╪╣┘ä┘ë ╪º┘ä┘à╪«╪»┘à: ${res.missingRemote}`,
        });
      }
    } catch (e: unknown) {
      addSqlSyncLogEntry({
        direction: 'system',
        action: 'attachments:pull',
        status: 'error',
        message: toErrorMessage(e, '┘ü╪┤┘ä ╪¬┘å╪▓┘è┘ä ╪º┘ä┘à╪▒┘ü┘é╪º╪¬'),
      });
    }
  }

  return 'upsert';
}

export async function startSqlPullLoop(): Promise<void> {
  await startBackgroundPull(
    async (row) => {
      await applySqlRemoteKvRow(row);
    },
    { runImmediately: true }
  );
}

export async function pushAllLocalToRemote(): Promise<{
  upsertsOk: number;
  deletesOk: number;
  errors: number;
}> {
  const keys = kvKeys();
  const concurrency = 8;
  let idx = 0;

  let upsertsOk = 0;
  let deletesOk = 0;
  let errors = 0;

  const worker = async () => {
    while (idx < keys.length) {
      const i = idx++;
      const k = keys[i];
      if (!k) continue;

      const deletedAt = kvGetDeletedAt(k);
      if (deletedAt) {
        try {
          await pushKvDelete({ key: k, deletedAt });
          addSqlSyncLogEntry({
            direction: 'push',
            action: 'delete',
            key: k,
            status: 'ok',
            ts: deletedAt,
          });
          deletesOk += 1;
        } catch (e: unknown) {
          addSqlSyncLogEntry({
            direction: 'push',
            action: 'delete',
            key: k,
            status: 'error',
            message: toErrorMessage(e, '┘ü╪┤┘ä ╪▒┘ü╪╣ ╪º┘ä╪¡╪░┘ü'),
          });
          errors += 1;
        }
        continue;
      }

      const meta = kvGetMeta(k);
      const v = kvGet(k);
      if (typeof v !== 'string') continue;
      const updatedAt = meta?.updatedAt || new Date().toISOString();
      try {
        await pushKvUpsert({ key: k, value: v, updatedAt });
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'upsert',
          key: k,
          status: 'ok',
          ts: updatedAt,
        });
        upsertsOk += 1;
      } catch (e: unknown) {
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'upsert',
          key: k,
          status: 'error',
          message: toErrorMessage(e, '┘ü╪┤┘ä ╪▒┘ü╪╣ ╪º┘ä╪¬╪¡╪»┘è╪½'),
        });
        errors += 1;
      }
    }
  };

  const workers = Array.from({ length: Math.min(concurrency, Math.max(1, keys.length)) }, () =>
    worker()
  );
  await Promise.all(workers);

  return { upsertsOk, deletesOk, errors };
}

export async function pushDeltaToRemoteSince(
  sinceIso: string
): Promise<{ upsertsOk: number; deletesOk: number; errors: number; latestTs: string }> {
  const updated = kvListUpdatedSince(sinceIso);
  const deleted = kvListDeletedSince(sinceIso);

  let upsertsOk = 0;
  let deletesOk = 0;
  let errors = 0;
  let latestTs =
    sinceIso && String(sinceIso).trim() ? String(sinceIso).trim() : '1970-01-01T00:00:00.000Z';

  const tasks: Array<() => Promise<void>> = [];

  for (const row of deleted) {
    const k = getStringField(row, 'k').trim();
    const deletedAt = getStringField(row, 'deletedAt').trim();
    if (!k || !deletedAt) continue;
    if (new Date(deletedAt).getTime() > new Date(latestTs).getTime()) latestTs = deletedAt;
    tasks.push(async () => {
      try {
        await pushKvDelete({ key: k, deletedAt });
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'delete',
          key: k,
          status: 'ok',
          ts: deletedAt,
        });
        deletesOk += 1;
      } catch (e: unknown) {
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'delete',
          key: k,
          status: 'error',
          message: toErrorMessage(e, '┘ü╪┤┘ä ╪▒┘ü╪╣ ╪º┘ä╪¡╪░┘ü'),
        });
        errors += 1;
      }
    });
  }

  for (const row of updated) {
    const k = getStringField(row, 'k').trim();
    const v = getField(row, 'v');
    const updatedAt = getStringField(row, 'updatedAt').trim();
    if (!k || typeof v !== 'string' || !updatedAt) continue;
    if (new Date(updatedAt).getTime() > new Date(latestTs).getTime()) latestTs = updatedAt;
    tasks.push(async () => {
      try {
        await pushKvUpsert({ key: k, value: v, updatedAt });
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'upsert',
          key: k,
          status: 'ok',
          ts: updatedAt,
        });
        upsertsOk += 1;
      } catch (e: unknown) {
        addSqlSyncLogEntry({
          direction: 'push',
          action: 'upsert',
          key: k,
          status: 'error',
          message: toErrorMessage(e, '┘ü╪┤┘ä ╪▒┘ü╪╣ ╪º┘ä╪¬╪¡╪»┘è╪½'),
        });
        errors += 1;
      }
    });
  }

  if (tasks.length === 0) return { upsertsOk, deletesOk, errors, latestTs };

  const concurrency = 6;
  let idx = 0;
  const worker = async () => {
    while (idx < tasks.length) {
      const i = idx++;
      const t = tasks[i];
      if (!t) continue;
      await t();
    }
  };
  await Promise.all(Array.from({ length: Math.min(concurrency, tasks.length) }, () => worker()));

  return { upsertsOk, deletesOk, errors, latestTs };
}

