            !localBestTs || new Date(remoteTs).getTime() > new Date(localBestTs).getTime();
          if (!isRemoteNewer) return;

          if (row.isDeleted) {
            kvApplyRemoteDelete(row.k, remoteTs);
            ipc.broadcastDbRemoteUpdate({ key: row.k, isDeleted: true, updatedAt: remoteTs });
