    if (result.canceled || result.filePaths.length === 0) {
      return { ok: false, canceled: true };
    }

    const filePath = result.filePaths[0];
    const raw = (await fsp.readFile(filePath, 'utf8')).trim();
    if (!raw) return { ok: false, error: '╪º┘ä┘à┘ä┘ü ┘ü╪º╪▒╪║.' };

