    }

    privateKeyBytes = bytes;
    const pub = await getPublicKeyAsync(privateKeyBytes);
    publicKeyB64 = bytesToBase64(pub);

    if (expectedPublicKeyB64 && !isPrivateKeyMatchingExpected(publicKeyB64)) {
      privateKeyBytes = null;
      publicKeyB64 = null;
      return {
        ok: false,
        error:
