const extractRoutePaths = (src) => {
  // Matches: KEY: '/value'
  const re = /^\s*[A-Z0-9_]+\s*:\s*'([^']+)'\s*,?\s*$/gm;
  const out = new Set();
  let m;
  while ((m = re.exec(src))) {
    const v = m[1];
    if (v.startsWith('/')) out.add(v);
  }
  return out;
};

const extractNavLiteralPaths = (src) => {
  // Matches: path: '/something'
  const re = /\bpath\s*:\s*'([^']+)'/g;
  const out = new Set();
  let m;
  while ((m = re.exec(src))) {
    const v = m[1];
    if (v.startsWith('/')) out.add(v);
  }
  return out;
};

const extractNavRoutePathRefs = (src) => {
  // Matches: path: ROUTE_PATHS.SOMETHING
  const re = /\bpath\s*:\s*ROUTE_PATHS\.([A-Z0-9_]+)/g;
  const out = new Set();
  let m;
  while ((m = re.exec(src))) out.add(m[1]);
  return out;
};

const extractAppRoutePathRefs = (src) => {
  // Matches: case ROUTE_PATHS.SOMETHING:
  const re = /\bcase\s+ROUTE_PATHS\.([A-Z0-9_]+)\s*:/g;
  const out = new Set();
  let m;
  while ((m = re.exec(src))) out.add(m[1]);
  // Also catch equality checks: currentHash !== ROUTE_PATHS.LOGIN
  const re2 = /\bROUTE_PATHS\.([A-Z0-9_]+)/g;
  while ((m = re2.exec(src))) out.add(m[1]);
  return out;
};

const extractTitleRoutePathRefs = (src) => {
  // Matches: titles[ROUTE_PATHS.SOMETHING] = '...'
  const re = /\btitles\s*\[\s*ROUTE_PATHS\.([A-Z0-9_]+)\s*\]\s*=\s*['"]/g;
  const out = new Set();
  let m;
  while ((m = re.exec(src))) out.add(m[1]);
  return out;
};

const main = () => {
  const srcPaths = read(pathsFile);
  const srcRegistry = read(registryFile);
  const srcApp = read(appFile);

  const routePaths = extractRoutePaths(srcPaths);
  const navLiterals = extractNavLiteralPaths(srcRegistry);

  const navRefs = extractNavRoutePathRefs(srcRegistry);
  const appRefs = extractAppRoutePathRefs(srcApp);
  const titleRefs = extractTitleRoutePathRefs(srcRegistry);

  const errors = [];

  // 1) No literal nav paths outside ROUTE_PATHS (excluding # anchors)
  if (navLiterals.size > 0) {
    errors.push(
      `NAV_ITEMS contains hard-coded literal paths: ${Array.from(navLiterals).join(', ')}`
    );
  }

  // 2) All ROUTE_PATHS used in registry/app should exist in ROUTE_PATHS definition
  const definedKeys = new Set();
  const keyRe = /^\s*([A-Z0-9_]+)\s*:\s*'[^']+'\s*,?\s*$/gm;
  let km;
  while ((km = keyRe.exec(srcPaths))) definedKeys.add(km[1]);

  for (const k of navRefs) {
    if (!definedKeys.has(k)) errors.push(`NAV_ITEMS references missing ROUTE_PATHS.${k}`);
  }
  for (const k of appRefs) {
    if (!definedKeys.has(k)) errors.push(`App references missing ROUTE_PATHS.${k}`);
  }

  // 3) Every ROUTE_PATHS.* must have a title guaranteed:
  // - either it appears in NAV_ITEMS (so ROUTE_TITLES derives it),
  // - or it has an explicit titles[ROUTE_PATHS.X] assignment.
  for (const k of definedKeys) {
    const coveredByNav = navRefs.has(k);
    const coveredExplicitly = titleRefs.has(k);
    if (!coveredByNav && !coveredExplicitly) {
      errors.push(`Missing ROUTE_TITLES coverage for ROUTE_PATHS.${k} (not in NAV_ITEMS and no explicit title)`);
    }
  }

  // 4) All ROUTE_PATHS values should look like routes
  for (const p of routePaths) {
    if (!p.startsWith('/')) errors.push(`Invalid route path (expected to start with '/'): ${p}`);
  }

  if (errors.length) {
    console.error('\n[routes:check] FAILED');
    for (const e of errors) console.error(' - ' + e);
    process.exit(1);
  }

  console.log(
    `[routes:check] OK (paths: ${routePaths.size}, nav refs: ${navRefs.size}, app refs: ${appRefs.size}, title refs: ${titleRefs.size})`
  );
};

main();

#!/usr/bin/env node
/**
 * Smoke Test - Simple HTTP-based verification (no Playwright)
 * Tests:
 * 1. Dev server startup
 * 2. Routes accessibility (HTTP 200)
 * 3. 404 page exists
 * 4. Health checks
 */

import { spawn } from 'node:child_process';
import { setTimeout as delay } from 'node:timers/promises';
import http from 'node:http';
import process from 'node:process';

const DEV_PORT = Number(process.env.SMOKE_PORT || 5173);
const DEV_HOST = process.env.SMOKE_HOST || '127.0.0.1';
const DEV_URL = `http://${DEV_HOST}:${DEV_PORT}`;

const NPM_CMD = process.platform === 'win32' ? 'npm.cmd' : 'npm';

function log(prefix, msg) {
  console.warn(`[${new Date().toISOString().slice(11, 23)}] ${prefix} ${msg}`);
}

function httpGet(url) {
  return new Promise((resolve, reject) => {
    const req = http.get(url, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        resolve({
          status: res.statusCode || 0,
          body: Buffer.concat(chunks).toString('utf8'),
        });
      });
    });
    req.on('error', reject);
    req.setTimeout(8000, () => {
      req.destroy(new Error(`Request timeout: ${url}`));
    });
  });
}

async function waitForServer(url, devProcess, timeoutMs = 60_000) {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    if (devProcess && devProcess.exitCode != null) {
      throw new Error(`Dev server exited early (code ${devProcess.exitCode})`);
    }
    try {
      const res = await httpGet(url);
      if (res.status >= 200 && res.status < 500) {
        log('Γ£ô', `Server ready at ${url}`);
        return true;
      }
    } catch {
      // retry
    }
    await delay(500);
  }
  throw new Error(`Server not ready within ${timeoutMs}ms`);
}

async function testRoute(path, expectStatus = 200) {
  try {
    const res = await httpGet(`${DEV_URL}${path}`);
    if (res.status === expectStatus) {
      log('Γ£ô', `Route ${path}: HTTP ${res.status}`);
      return true;
    } else {
      log('Γ£ù', `Route ${path}: HTTP ${res.status} (expected ${expectStatus})`);
      return false;
    }
  } catch (e) {
    log('Γ£ù', `Route ${path}: ${e.message}`);
    return false;
  }
}

async function main() {
  log('START', 'Smoke test begins');

  // If a dev server is already running on the target URL, don't try to spawn a new one.
  // This avoids "Port already in use" hangs/failures when another Vite instance is open.
  let existingServer = false;
  try {
    const res = await httpGet(DEV_URL);
    if (res.status >= 200 && res.status < 500) existingServer = true;
  } catch {
    // not running
  }

  if (existingServer) {
    log('INFO', `Dev server already running at ${DEV_URL} (skipping spawn)`);
  }

  const devArgs = ['run', 'dev', '--', '--host', DEV_HOST, '--port', String(DEV_PORT), '--strictPort'];
  const dev = existingServer
    ? null
    : process.platform === 'win32'
      ? spawn(process.env.ComSpec || 'cmd.exe', ['/d', '/s', '/c', `npm ${devArgs.join(' ')}`], {
          cwd: process.cwd(),
          shell: false,
          stdio: 'pipe',
          env: { ...process.env, BROWSER: 'none' },
          windowsHide: true,
        })
      : spawn(NPM_CMD, devArgs, {
          cwd: process.cwd(),
          shell: false,
          stdio: 'pipe',
          env: { ...process.env, BROWSER: 'none' },
        });

  let _devOutput = '';
  if (dev) {
    dev.stdout.on('data', (d) => {
      const text = d.toString('utf8');
      _devOutput += text;
      // Only log key messages
      if (text.includes('ready in') || text.toLowerCase().includes('error')) {
        process.stdout.write(text);
      }
    });

    dev.stderr.on('data', (d) => process.stderr.write(d.toString('utf8')));
  }

  try {
    log('WAIT', 'Waiting for dev server...');
    await waitForServer(DEV_URL, dev, 45_000);

    log('TEST', 'Starting route tests');

    const routes = [
      { path: '/', label: 'Dashboard (index)' },
      { path: '/#/', label: 'Dashboard (hash)' },
      { path: '/#/people', label: 'People' },
      { path: '/#/properties', label: 'Properties' },
      { path: '/#/contracts', label: 'Contracts' },
      { path: '/#/installments', label: 'Installments' },
      { path: '/#/settings', label: 'Settings' },
      { path: '/#/login', label: 'Login' },
    ];

    let passed = 0;
    let failed = 0;

    for (const r of routes) {
      const ok = await testRoute(r.path);
      if (ok) passed++;
      else failed++;
      await delay(300);
    }

    // Test 404
    log('TEST', 'Testing 404 fallback');
    const notFound = await testRoute('/#/this-route-does-not-exist', 200);
    if (notFound) {
      log('Γ£ô', 'NotFound route responds with HTTP 200 (renders 404 page)');
      passed++;
    } else {
      log('Γ£ù', 'NotFound route failed');
      failed++;
    }

    log('SUMMARY', `Routes: ${passed} passed, ${failed} failed`);

    if (failed === 0) {
      log('Γ£ôΓ£ôΓ£ô', 'All smoke tests PASSED');
      process.exitCode = 0;
    } else {
      log('Γ£ùΓ£ùΓ£ù', `${failed} test(s) FAILED`);
      process.exitCode = 1;
    }
  } catch (err) {
    log('ERROR', `${err.message}`);
    process.exitCode = 1;
  } finally {
    if (!existingServer) {
      log('CLEANUP', 'Stopping dev server');
      try {
        dev?.kill();
        await delay(1500);

        if (dev && dev.exitCode == null) {
          if (process.platform === 'win32') {
            spawn('taskkill', ['/PID', String(dev.pid), '/T', '/F'], {
              cwd: process.cwd(),
              stdio: 'ignore',
              shell: false,
              windowsHide: true,
            });
          } else {
            dev.kill('SIGKILL');
          }
        }
      } catch {
        // ignore
      }
    }
  }
}

await main();

