const http = require('http');
const fs = require('fs');
const fsp = require('fs/promises');
const path = require('path');
const crypto = require('crypto');

const PORT = Number(process.env.MARQUEE_PORT || process.env.PORT || 5055);
const HOST = process.env.MARQUEE_HOST || '0.0.0.0';

const dataDir = path.join(__dirname, 'data');
const dataFile = path.join(dataDir, 'marquee.json');

// ================== Rate Limiting ==================
// SECURITY: Protect against brute-force and DoS attacks
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100; // max requests per window for read operations
const RATE_LIMIT_WRITE_MAX = 20; // stricter for write operations (POST/DELETE)
const rateLimitStore = new Map();

// SECURITY WARNING: X-Forwarded-For can be spoofed. Only trust this header
// if the server is behind a trusted reverse proxy. For production deployments
// behind a proxy, set MARQUEE_TRUST_PROXY=1 to use X-Forwarded-For.
// Otherwise, the direct socket IP will be used.
function getRateLimitKey(req) {
  const trustProxy = String(process.env.MARQUEE_TRUST_PROXY || '').trim() === '1';
  if (trustProxy) {
    const forwarded = req.headers['x-forwarded-for'];
    if (forwarded) {
      return String(forwarded).split(',')[0].trim();
    }
  }
  return req.socket?.remoteAddress || 'unknown';
}

function checkRateLimit(req, isWrite = false) {
  const key = getRateLimitKey(req);
  const now = Date.now();
  const maxRequests = isWrite ? RATE_LIMIT_WRITE_MAX : RATE_LIMIT_MAX_REQUESTS;
  
  let record = rateLimitStore.get(key);
  if (!record || now - record.windowStart > RATE_LIMIT_WINDOW_MS) {
    record = { windowStart: now, count: 0 };
  }
  
  record.count++;
  rateLimitStore.set(key, record);
  
  // Cleanup old entries
  if (rateLimitStore.size > 1000) {
    const threshold = now - RATE_LIMIT_WINDOW_MS * 2;
    for (const [k, v] of rateLimitStore) {
      if (v.windowStart < threshold) rateLimitStore.delete(k);
    }
  }
  
  if (record.count > maxRequests) {
    const retryAfter = Math.ceil((record.windowStart + RATE_LIMIT_WINDOW_MS - now) / 1000);
    return { allowed: false, retryAfter };
  }
  
  return { allowed: true, remaining: maxRequests - record.count };
}
// ================== End Rate Limiting ==================

function nowIso() {
  return new Date().toISOString();
}

function sendJson(res, statusCode, body, headers = {}) {
  const payload = Buffer.from(JSON.stringify(body ?? null));
  res.writeHead(statusCode, {
    'Content-Type': 'application/json; charset=utf-8',
    'Content-Length': payload.length,
    ...headers,
  });
  res.end(payload);
}

// SECURITY NOTE: CORS is set to '*' for backwards compatibility.
// For production, consider setting MARQUEE_CORS_ORIGIN to restrict allowed origins.
function setCors(res, req) {
  const allowedOrigin = String(process.env.MARQUEE_CORS_ORIGIN || '').trim() || '*';
  const requestOrigin = req?.headers?.origin;
  
  if (allowedOrigin !== '*' && requestOrigin) {
    const allowedOrigins = allowedOrigin.split(',').map(o => o.trim());
    if (allowedOrigins.includes(requestOrigin)) {
      res.setHeader('Access-Control-Allow-Origin', requestOrigin);
      res.setHeader('Vary', 'Origin');
    }
    // SECURITY: Don't set CORS header if origin is not in allowed list
    // This prevents unauthorized cross-origin requests
  } else if (allowedOrigin === '*') {
    res.setHeader('Access-Control-Allow-Origin', '*');
  } else if (!requestOrigin) {
    // No origin header means same-origin request, allow it
    res.setHeader('Access-Control-Allow-Origin', allowedOrigin.split(',')[0]?.trim() || '*');
  }
  
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,DELETE,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, If-Match');
  res.setHeader('Access-Control-Expose-Headers', 'ETag');
  res.setHeader('Access-Control-Max-Age', '86400');
}

async function ensureStore() {
  await fsp.mkdir(dataDir, { recursive: true });
  if (!fs.existsSync(dataFile)) {
    await fsp.writeFile(dataFile, JSON.stringify({ items: [] }, null, 2), 'utf8');
  }
}

async function readStore() {
  await ensureStore();
  const raw = await fsp.readFile(dataFile, 'utf8');
  try {
    const json = JSON.parse(raw);
    if (!json || !Array.isArray(json.items)) return { items: [] };
    return json;
  } catch {
    return { items: [] };
  }
}

async function writeStore(store) {
  await ensureStore();
  await fsp.writeFile(dataFile, JSON.stringify(store, null, 2), 'utf8');
}

function computeEtag(content) {
  return 'W/"' + crypto.createHash('sha1').update(content).digest('hex') + '"';
}

function isExpired(item) {
  if (!item?.expiresAt) return false;
  const t = Date.parse(String(item.expiresAt));
  if (!Number.isFinite(t)) return false;
  return Date.now() > t;
}

async function getActiveItemsAndMaybeClean() {
  const store = await readStore();
  const before = store.items || [];
  const active = before.filter(it => !isExpired(it));
  if (active.length !== before.length) {
    await writeStore({ items: active });
  }
  return active;
}

async function readBodyJson(req) {
  const chunks = [];
  for await (const chunk of req) chunks.push(chunk);
  const raw = Buffer.concat(chunks).toString('utf8');
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

const server = http.createServer(async (req, res) => {
  setCors(res, req);

  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  const url = new URL(req.url || '/', `http://${req.headers.host || 'localhost'}`);

  // SECURITY: Apply rate limiting
  const isWriteOperation = req.method === 'POST' || req.method === 'DELETE';
  const rateLimitResult = checkRateLimit(req, isWriteOperation);
  if (!rateLimitResult.allowed) {
    res.setHeader('Retry-After', String(rateLimitResult.retryAfter || 60));
    return sendJson(res, 429, { 
      ok: false, 
      message: 'Too Many Requests. Please try again later.',
      retryAfter: rateLimitResult.retryAfter
    });
  }

  try {
    if (req.method === 'GET' && url.pathname === '/health') {
      sendJson(res, 200, { ok: true, time: nowIso() });
      return;
    }

    if (url.pathname === '/api/marquee' && req.method === 'GET') {
      const items = await getActiveItemsAndMaybeClean();
      const raw = JSON.stringify({ items });
      const etag = computeEtag(raw);
      res.setHeader('ETag', etag);
      if (req.headers['if-none-match'] === etag) {
        res.writeHead(304);
        res.end();
        return;
      }
      sendJson(res, 200, { items }, { ETag: etag });
      return;
    }

    if (url.pathname === '/api/marquee' && req.method === 'POST') {
      const body = await readBodyJson(req);
      const content = String(body?.content ?? '').trim();
      if (!content) {
        sendJson(res, 400, { message: 'content is required' });
        return;
      }

      const durationHours = Number(body?.durationHours ?? 0);
      const expiresAt = body?.expiresAt ? String(body.expiresAt) : (durationHours > 0 ? new Date(Date.now() + durationHours * 3600_000).toISOString() : null);

      const record = {
        id: 'srv_' + crypto.randomBytes(8).toString('hex'),
        content,
        type: String(body?.type ?? 'info'),
        priority: String(body?.priority ?? 'Normal'),
        createdAt: nowIso(),
        expiresAt: expiresAt || undefined,
      };

      const store = await readStore();
      const next = { items: [record, ...(store.items || [])] };
      await writeStore(next);

      sendJson(res, 201, { item: record });
      return;
    }

    if (req.method === 'DELETE' && url.pathname.startsWith('/api/marquee/')) {
      const id = decodeURIComponent(url.pathname.substring('/api/marquee/'.length));
      const store = await readStore();
      const before = store.items || [];
      const after = before.filter(it => String(it?.id) !== id);
      await writeStore({ items: after });
      sendJson(res, 200, { success: true });
      return;
    }

    sendJson(res, 404, { message: 'Not Found' });
  } catch (e) {
    console.error(e);
    sendJson(res, 500, { message: 'Internal Server Error' });
  }
});

server.listen(PORT, HOST, () => {
  console.log(`[marquee-server] listening on http://${HOST}:${PORT}`);
});

