    window.addEventListener('keydown', onKeyDown);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
      unlockBodyScroll();
    };
  }, [isDesktop, sidebarOpen]);

  const toggleTheme = () => {
    const newMode = !isDark;
    setIsDark(newMode);
    try {
      void storage.setItem('theme', newMode ? 'dark' : 'light');
    } catch {
