interface RouterPageProps {
    path: string;
}

export const RouterPage: React.FC<RouterPageProps> = ({ path }) => {
    let Component: React.LazyExoticComponent<React.FC<any>> | null = null;

    switch (path) {
        case ROUTE_PATHS.DASHBOARD: Component = Dashboard; break;
        case ROUTE_PATHS.SALES: Component = Sales; break;
        case ROUTE_PATHS.PEOPLE: Component = People; break;
        case ROUTE_PATHS.PROPERTIES: Component = Properties; break;
        case ROUTE_PATHS.CONTRACTS: Component = Contracts; break;
        case ROUTE_PATHS.INSTALLMENTS: Component = Installments; break;
        case ROUTE_PATHS.COMMISSIONS: Component = Commissions; break;
        case ROUTE_PATHS.MAINTENANCE: Component = Maintenance; break;
        case ROUTE_PATHS.ALERTS: Component = Alerts; break;
        case ROUTE_PATHS.REPORTS: Component = Reports; break;
        case ROUTE_PATHS.LEGAL: Component = LegalHub; break;
        case ROUTE_PATHS.SMART_TOOLS: Component = SmartTools; break;
        case ROUTE_PATHS.ADMIN_PANEL: Component = AdminControlPanel; break;
        case ROUTE_PATHS.SETTINGS: Component = Settings; break;
        case ROUTE_PATHS.BACKUP: Component = BackupManager; break;
        case ROUTE_PATHS.OPERATIONS: Component = Operations; break;
        case ROUTE_PATHS.SYS_MAINTENANCE: Component = SystemMaintenance; break;
        case ROUTE_PATHS.BUILDER: Component = DynamicBuilder; break;
        case ROUTE_PATHS.DOCS: Component = Documentation; break;
        case ROUTE_PATHS.OWNER_PORTAL: Component = OwnerPortal; break;
        case ROUTE_PATHS.CONTACTS: Component = Contacts; break;
        case ROUTE_PATHS.BULK_WHATSAPP: Component = BulkWhatsApp; break;
        case ROUTE_PATHS.DOCUMENTS: Component = Documents; break;
        case ROUTE_PATHS.COMPREHENSIVE_TESTS: Component = ComprehensiveTests; break;
        case ROUTE_PATHS.LICENSE_ADMIN: Component = LicenseAdmin; break;
        default: Component = NotFound; break;
    }

    return (
        <Suspense fallback={<PageLoader />}>
            {Component && <Component />}
        </Suspense>
    );
};

import React, { useRef, useEffect } from 'react';
import { useTabs, Tab } from '@/context/TabsContext';
import { X, Pin, Plus } from 'lucide-react';
import { ROUTE_ICONS } from '@/routes/registry';

export const TabBar: React.FC = () => {
    const { tabs, activeTabId, closeTab, switchTab, pinTab, reorderTabs } = useTabs();
    const scrollRef = useRef<HTMLDivElement>(null);

    // Auto-scroll to active tab
    useEffect(() => {
        if (scrollRef.current) {
            const activeEl = scrollRef.current.querySelector(`[data-id="${activeTabId}"]`);
            if (activeEl) {
                activeEl.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
            }
        }
    }, [activeTabId]);

    const handleDragStart = (e: React.DragEvent, index: number) => {
        e.dataTransfer.setData('tabIndex', index.toString());
    };

    const handleDrop = (e: React.DragEvent, toIndex: number) => {
        const fromIndex = parseInt(e.dataTransfer.getData('tabIndex'), 10);
        if (fromIndex !== toIndex) {
            reorderTabs(fromIndex, toIndex);
        }
    };

    const handleWheel = (e: React.WheelEvent) => {
        if (scrollRef.current) {
            scrollRef.current.scrollLeft += e.deltaY;
        }
    };

    return (
        <div className="mx-4 lg:mx-8 mt-2 flex items-center bg-slate-900/40 backdrop-blur-md border border-white/5 rounded-2xl px-3 h-14 select-none shadow-2xl shadow-black/20">
            <div 
                ref={scrollRef}
                onWheel={handleWheel}
                className="flex-1 flex items-center overflow-x-auto no-scrollbar gap-2 h-full py-2"
            >
                {tabs.map((tab, idx) => {
                    const isActive = tab.id === activeTabId;
                    const Icon = (ROUTE_ICONS as Record<string, any>)[tab.path];

                    return (
                        <div
                            key={tab.id}
                            data-id={tab.id}
                            draggable
                            onDragStart={(e) => handleDragStart(e, idx)}
                            onDragOver={(e) => e.preventDefault()}
                            onDrop={(e) => handleDrop(e, idx)}
                            onClick={() => switchTab(tab.id)}
                            className={`
                                group relative flex items-center gap-2.5 px-4 h-10 min-w-[140px] max-w-[220px] rounded-xl transition-all duration-300 cursor-pointer
                                ${isActive 
                                    ? 'bg-gradient-to-r from-indigo-600 to-indigo-500 text-white shadow-lg shadow-indigo-600/20' 
                                    : 'text-slate-400 hover:bg-white/5 hover:text-slate-100'}
                            `}
                        >
                            <div className={`p-1 rounded-lg ${isActive ? 'bg-white/20' : 'bg-slate-800/40'}`}>
                                {Icon ? <Icon size={14} strokeWidth={2.5} /> : <span className="text-xs">{tab.icon}</span>}
                            </div>

                            <span className={`text-[13px] font-bold truncate flex-1 ${isActive ? 'text-white' : ''}`}>
                                {tab.title}
                            </span>

                            {tab.isModified && (
                                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-slate-900 animate-pulse" />
                            )}

                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button
                                    onClick={(e) => { e.stopPropagation(); pinTab(tab.id); }}
                                    className={`p-1 rounded-lg transition-colors ${isActive ? 'hover:bg-white/20' : 'hover:bg-slate-700'} ${tab.isPinned ? (isActive ? 'text-white' : 'text-indigo-400') : 'text-slate-500'}`}
                                >
                                    <Pin size={12} className={tab.isPinned ? 'fill-current' : ''} />
                                </button>

                                {(!tab.isPinned && tab.id !== 'home') && (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); closeTab(tab.id); }}
                                        className={`p-1 rounded-lg transition-colors ${isActive ? 'hover:bg-white/20' : 'hover:bg-red-500/20 hover:text-red-400'}`}
                                    >
                                        <X size={12} />
                                    </button>
                                )}
                            </div>

                            {tab.isPinned && !tab.id.includes('home') && (
                                <div className="absolute -top-1 -left-1">
                                    <Pin size={10} className="text-indigo-400 fill-current" />
                                </div>
                            )}
                        </div>
                    );
                })}

                <button 
                    className="flex-shrink-0 w-10 h-10 flex items-center justify-center bg-white/5 text-slate-400 hover:text-white hover:bg-indigo-600/20 hover:border-indigo-500/30 border border-transparent rounded-xl transition-all"
                    onClick={() => {
                        window.dispatchEvent(new CustomEvent('azrar:open-page-selector'));
                    }}
                    title="┘ü╪¬╪¡ ╪╡┘ü╪¡╪⌐ ╪¼╪»┘è╪»╪⌐ (Ctrl+T)"
                >
                    <Plus size={20} />
                </button>
            </div>
        </div>
    );
};

