          footer={
            <div className="flex justify-end gap-3">
              <Button type="button" variant="secondary" onClick={() => setIsAddTemplateOpen(false)}>
                ╪Ñ┘ä╪║╪º╪í
              </Button>
              <Button type="submit" variant="primary" form="add-template-form">
                ╪¡┘ü╪╕ ╪º┘ä┘å┘à┘ê╪░╪¼
              </Button>
