          }
        >
          <form id="add-template-form" onSubmit={handleAddTemplate} className="space-y-4">
            <div>
              <label className="block text-sm font-bold mb-1">╪╣┘å┘ê╪º┘å ╪º┘ä┘å┘à┘ê╪░╪¼</label>
              <input
