const normalizeSearchTerm = (str: string): string => {
  if (!str) return '';
  return String(str)
    .normalize('NFKD')
    .replace(/[\u064B-\u065F\u0610-\u061A]/g, '')
    .replace(/[┘è┘ë╪ª]/g, '┘è')
    .replace(/[╪ñ┘ê]/g, '┘ê')
    .replace(/[╪⌐┘ç]/g, '┘ç')
    .replace(/[\s\-_.,]/g, '')
    .toLowerCase()
    .trim();
};

