  }
): DbResult<string> => {
  const { sanitizeMarqueeText, sanitizeAction } = createMarqueeActionSanitizers(MARQUEE_ALLOWED_PANELS);

  const content = sanitizeMarqueeText(data?.content, 300);
  if (!content) return fail('┘å╪╡ ╪º┘ä╪Ñ╪╣┘ä╪º┘å ┘à╪╖┘ä┘ê╪¿');

