      // 791111111 -> 962791111111
      expect(normalizeWhatsAppPhone('791111111', { defaultCountryCode: '962' })).toBe('962791111111');
    });

    it('returns empty string for invalid input', () => {
      expect(normalizeWhatsAppPhone('abc')).toBe('');
